#!/bin/bash
# PostToolUse hook (matcher: Workflow). Fires after every successful Workflow launch;
# reminds the model to scaffold long-run recovery and to make the ARM decision explicitly.
jq -n '{hookSpecificOutput:{hookEventName:"PostToolUse",additionalContext:"[long-run-recovery] A Workflow was just launched. If it can run >1h, scaffold recovery per ~/.claude/CLAUDE.md section \"Long-run recovery\": (1) write/update this pipeline'\''s own state entry ~/.claude/long-run-state/<project>-<short-run-id>.json (status:running, project, runId, scriptPath, currentPhase, resumeProtocol, updatedAt) and set autoResume EXPLICITLY - true ONLY if the user asked for unattended/self-healing execution of this pipeline, otherwise false (halts then stay halted for the user to decide; user controls: longrun arm|disarm|done|reopen <id>); (2) if armed, ensure an in-session heartbeat exists (on a usage-limit halt, also record nextResetEpoch in the state entry); (3) the workflow script must have a circuit breaker: an agent dying twice halts the run cleanly at that unit. When the pipeline finishes: set its status to done (silences all recovery layers for it)."}}'
